diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index d81ed56290476..0813eebe70f64 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -2506,6 +2506,26 @@ Instruction *InstCombinerImpl::visitAnd(BinaryOperator &I) {
       return BinaryOperator::CreateOr(And, ConstantInt::get(Ty, Together));
     }

+    // ((X | C1) >> N) & C2 --> ((X >> N) & C2) | ((C1 >> N) & C2)
+    // This reassociates the and-mask through the shift to expose a constant
+    // that can be folded into GEP offsets.
+    // Only profitable when the or is disjoint, enabling the transformation.
+    const APInt *DisjointOrC, *ShAmtN;
+    if (match(Op0,
+              m_OneUse(m_LShr(m_DisjointOr(m_Value(X), m_APInt(DisjointOrC)),
+                              m_APInt(ShAmtN))))) {
+      unsigned ShAmt = ShAmtN->getZExtValue();
+      // Compute the constant result: (C1 >> N) & C2
+      APInt ConstResult = DisjointOrC->lshr(ShAmt) & *C;
+
+      // Create: (X >> N) & C2
+      Value *NewLShr = Builder.CreateLShr(X, ConstantInt::get(Ty, *ShAmtN));
+      Value *NewAnd = Builder.CreateAnd(NewLShr, ConstantInt::get(Ty, *C));
+      // Create: ((X & (C2 << N)) >> N) | ((C1 >> N) & C2)
+      return BinaryOperator::CreateDisjointOr(
+          NewAnd, ConstantInt::get(Ty, ConstResult));
+    }
+
     unsigned Width = Ty->getScalarSizeInBits();
     const APInt *ShiftC;
     if (match(Op0, m_OneUse(m_SExt(m_AShr(m_Value(X), m_APInt(ShiftC))))) &&

tests.test_body:
define i32 @and_lshr_or_non_disjoint(i32 %val) {
  %or = or i32 %val, 32768
  %lshr = lshr i32 %or, 4
  %and = and i32 %lshr, 2800
  ret i32 %and
}

define i32 @and_ashr_disjoint_or(i32 %val) {
  %or = or disjoint i32 %val, 32768
  %ashr = ashr i32 %or, 4
  %and = and i32 %ashr, 2800
  ret i32 %and
}

define i32 @and_lshr_disjoint_or(i32 %val) {
  %or = or disjoint i32 %val, 32768
  %lshr = lshr i32 %or, 4
  %and = and i32 %lshr, 2800
  ret i32 %and
}

define i64 @and_lshr_disjoint_or_i64(i64 %val) {
  %or = or disjoint i64 %val, 32768
  %lshr = lshr i64 %or, 4
  %and = and i64 %lshr, 2800
  ret i64 %and
}

define i32 @and_lshr_disjoint_or_exact(i32 %val) {
  %or = or disjoint i32 %val, 32768
  %lshr = lshr exact i32 %or, 4
  %and = and i32 %lshr, 2800
  ret i32 %and
}

define i32 @and_lshr_disjoint_or_different_constant(i32 %val) {
  %or = or disjoint i32 %val, 32800
  %lshr = lshr exact i32 %or, 4
  %and = and i32 %lshr, 2800
  ret i32 %and
}

define i32 @and_lshr_disjoint_or_larger_shift(i32 %val) {
  %or = or disjoint i32 %val, 4080
  %lshr = lshr i32 %or, 8
  %and = and i32 %lshr, 255
  ret i32 %and
}

define <4 x i32> @and_lshr_disjoint_or_vec(<4 x i32> %val) {
  %or = or disjoint <4 x i32> %val, splat (i32 32768)
  %lshr = lshr <4 x i32> %or, splat (i32 4)
  %and = and <4 x i32> %lshr, splat (i32 2800)
  ret <4 x i32> %and
}

define i32 @and_lshr_disjoint_or_const_result_zero(i32 %val) {
  %or = or disjoint i32 %val, 128
  %lshr = lshr i32 %or, 8
  %and = and i32 %lshr, 255
  ret i32 %and
}
